sigma.retro_hunt_query:
// RETRO-HUNT: intel--ff51162f3a8787497d6030f6 | Techniques: T1190, T1059 | Lookback: 90d
// Generated by APEX Detection Validation Engine v162.0.0
let lookback = 90d;
let indicators = dynamic(["<indicator>"]);
union DeviceProcessEvents, DeviceNetworkEvents, DeviceFileEvents
| where TimeGenerated > ago(lookback)
| where ProcessCommandLine has_any (indicators)
    or RemoteUrl has_any (indicators)
    or FileName has_any (indicators)
| summarize HuntHits=count(), FirstSeen=min(TimeGenerated),
    LastSeen=max(TimeGenerated), Devices=dcount(DeviceName)
    by DeviceName, ProcessCommandLine, ThreatScore=80
| where HuntHits > 0 | order by HuntHits desc

retro_hunt.kql_sentinel:
// ============================================================
// RETRO-HUNT: intel--ff51162f3a8787497d6030f6
// Title   : CVE-2026-9459 - Edimax EW-7438RPn formConnectionSetting stack-based overflow
// Techniques: T1190, T1059
// Platform: Microsoft Sentinel (KQL)
// Lookback: 90 days
// Generated: CYBERDUDEBIVASH SENTINEL APEX v162.0.0
// ============================================================
let lookback = 90d;
let malicious_ips = dynamic(["<ip_indicator>"]);
let malicious_domains = dynamic(["<domain_indicator>"]);
let malicious_hashes = dynamic(["<hash_indicator>"]);
// --- NETWORK INDICATORS ---
let network_hits = union DeviceNetworkEvents, DnsEvents
| where TimeGenerated > ago(lookback)
| where RemoteIP has_any (malicious_ips)
    or DnsQuestion_Name has_any (malicious_domains)
    or RemoteUrl has_any (malicious_domains)
| project TimeGenerated, DeviceName, ActionType, RemoteIP, RemoteUrl,
          DnsQuestion_Name, InitiatingProcessCommandLine,
          HuntCategory="Network-Indicator";
// --- FILE/HASH INDICATORS ---
let file_hits = DeviceFileEvents
| where TimeGenerated > ago(lookback)
| where SHA256 has_any (malicious_hashes)
    or MD5 has_any (malicious_hashes)
| project TimeGenerated, DeviceName, ActionType, FileName, FolderPath,
          SHA256, MD5, InitiatingProcessCommandLine,
          HuntCategory="File-Hash";
// --- PROCESS INDICATORS ---
let process_hits = DeviceProcessEvents
| where TimeGenerated > ago(lookback)
| where SHA256 has_any (malicious_hashes)
    or MD5 has_any (malicious_hashes)
    or ProcessCommandLine contains "CVE-2026-9058" or ProcessCommandLine contains "CVE-2026-9459" or ProcessCommandLine contains "CVE-2026-9460"
| project TimeGenerated, DeviceName, FileName, ProcessCommandLine,
          InitiatingProcessFileName, SHA256, AccountName,
          HuntCategory="Process-Indicator";
// --- COMBINE ALL HITS ---
union network_hits, file_hits, process_hits
| summarize HuntHits=count(), FirstSeen=min(TimeGenerated), LastSeen=max(TimeGenerated),
    AffectedDevices=dcount(DeviceName), Categories=make_set(HuntCategory)
    by DeviceName, HuntCategory
| extend AdvisoryID="intel--ff51162f3a8787497d6030f6", Techniques="T1190, T1059",
    DaysSinceFirst=datetime_diff('day', now(), FirstSeen)
| order by HuntHits desc, DaysSinceFirst asc

retro_hunt.elastic_eql:
/* RETRO-HUNT EQL: intel--ff51162f3a8787497d6030f6 | Techniques: T1190, T1059 | Lookback: 90d */
sequence with maxspan=90d
  [network where
    destination.ip in ("<ip>")
    or dns.question.name in ("<domain>")
  ] by host.id
  [process where
    process.hash.sha256 in ("<hash>")
    or process.hash.md5 in ("<hash>")
  ] by host.id

retro_hunt.chronicle_udm:
/* RETRO-HUNT CHRONICLE UDM: intel--ff51162f3a8787497d6030f6 | Techniques: T1190, T1059 | Lookback: 90d */
/* Google SecOps (Chronicle) UDM Search */
metadata.event_timestamp.seconds > unix_seconds(timestamp_sub(current_timestamp(), interval 90 day))
AND (
    (target.ip = "<ip>")
    OR (network.dns.questions.name = "<domain>")
    OR (target.file.sha256 = "<hash>")
)
/* Aggregate by principal hostname */
| group_by principal.hostname
| order_by count() desc

